class TreeAncestor:
    def __init__(self, n, parent):
        log = max(1, n.bit_length() + 1)
        self.up = [[-1] * n for _ in range(log)]
        self.up[0] = parent[:]
        for j in range(1, log):
            for v in range(n):
                mid = self.up[j - 1][v]
                self.up[j][v] = -1 if mid == -1 else self.up[j - 1][mid]

    def getKthAncestor(self, node, k):
        j = 0
        while k > 0 and node != -1:
            if k & 1:
                node = self.up[j][node]
            k >>= 1
            j += 1
        return node

