var TreeAncestor = function(n, parent) {
    let log = 1;
    while ((1 << log) < n) log++;
    log += 1;
    this.up = [];
    this.up.push(parent.slice());
    for (let j = 1; j < log; j++) {
        const prev = this.up[j - 1];
        const cur = new Array(n).fill(-1);
        for (let v = 0; v < n; v++) {
            const mid = prev[v];
            cur[v] = mid === -1 ? -1 : prev[mid];
        }
        this.up.push(cur);
    }
};

TreeAncestor.prototype.getKthAncestor = function(node, k) {
    let j = 0;
    while (k > 0 && node !== -1) {
        if (k & 1) node = this.up[j][node];
        k >>= 1;
        j += 1;
    }
    return node;
};
